const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const projectTitle = $('workflow_trigger').first().json.project_title;
const operation = $('workflow_trigger').first().json.operation || 'get';
const userId = $('workflow_trigger').first().json.user_id || '';

// Find the project
let project = null;
try {
  let projectUrl = supabaseUrl + '/rest/v1/writing_projects_v2?title=eq.' + encodeURIComponent(projectTitle) + '&limit=1';
  if (userId) projectUrl += '&user_id=eq.' + userId;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: projectUrl,
    headers: headers
  });
  const projects = Array.isArray(resp) ? resp : [resp];
  if (projects.length > 0 && projects[0]?.id) {
    project = projects[0];
  }
} catch (e) {}

if (!project) {
  return [{ json: { project: null, error: 'Project not found: ' + projectTitle, operation: operation, user_id: userId } }];
}

return [{ json: { project: project, operation: operation, user_id: userId } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const projectId = $('get_project').first().json.project?.id;
const userId = $('get_project').first().json.user_id || '';

if (!projectId) {
  return [{ json: { result: 'Error: Project not found. Cannot update story bible.' } }];
}

const entriesStr = $('workflow_trigger').first().json.entries || '[]';
let entries = [];
try {
  entries = JSON.parse(entriesStr);
} catch (e) {
  // entries might already be an array/object
  entries = Array.isArray(entriesStr) ? entriesStr : [entriesStr];
}

const enriched = entries.map(e => ({ ...e, project_id: projectId, ...(userId ? { user_id: userId } : {}) }));

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/story_bible_v2',
    headers: headers,
    body: enriched
  });
} catch (e) {
  return [{ json: { result: 'Error updating story bible: ' + e.message } }];
}

return [{ json: { result: 'Story bible updated with ' + entries.length + ' entries for project ' + $('workflow_trigger').first().json.project_title } }];
